func GetItemID(name string) int32 {
	if id, ok := ItemByName[name]; ok {
		return id
	}
	return -1
}

func GetItemInfo(id int32) *ItemInfo {
	if id < 0 || int(id) >= len(Items) {
		return nil
	}
	return &Items[id]
}
